@module chrome  src=chrome.lua  loc=700  sha=ec591ad  mode=chunk
@deps cm, ctx

# Shapes
  @shape  chrome = { colour(name, scope?)->u32, pushChromeStyles(), popChromeStyles(), pushChromeWindow(), popChromeWindow(), verticalSeparator(), disabledIf(cond,fn), row(h?,fn), checkbox(label,v), radio(label,active), headingLabel(text), screenPainter()->painter}  @ 3
  @shape  chrome (pickers) = { makeToolbar()->fn(segments), drawPicker(d), libPicker(key, current, excludeOthers?)->items, pickerIsActive()->bool, resetPickerActive(), requestPickerOpen(kind) }  @ 4
  @shape  chrome (shared row primitives) = { fitLabel(text,maxW)->text, rowSelectable(label,sel,flags?)->clicked, treeRow(opts)->{toggled,selected,doubleClicked}, numberStepper(id,value,opts)->changed,value }  @ 5
  @shape  pickerSpec = { kind: string, heading: string?, buttonLabel: string, items: [{label, key, group?=int, current?=bool}], onPick: fn(key), onCancel?: fn(), placement?: 'above', width?, minWidth?, maxWidth?, flat?: bool }  @ 6
  @shape  palettePaneSpec = { x, y, h, label | {tabs=[{key,label}], activeTab, onTab}, draw = fn(childFocused) }  @ 7
  @shape  toolbarSegment = { id: string, render: fn, visible?: fn() -> bool }  @ 270

# Imports
  @require ImGui = 'imgui'  @ 10
      @contract  one chrome instance per coordinator; threaded into every page  @ 8
      @invariant  colour cache lives on the chrome instance and is invalidated on cm:configChanged  @ 9
  @require painter = 'painter'  @ 11

